class PRNG {

  uint64_t s;

  uint64_t rand64() {

    s ^= s >> 12, s ^= s << 25, s ^= s >> 27;
    return s * 2685821657736338717LL;
  }

public:
  PRNG(uint64_t seed) : s(seed) { (static_cast<void>(0)); }

  template<typename T> T rand() { return T(rand64()); }



  template<typename T> T sparse_rand()
  { return T(rand64() & rand64() & rand64()); }
};
