        Bitboard b1 = shift<Right>(pawnsOn7) & enemies;
        Bitboard b2 = shift<Left >(pawnsOn7) & enemies;
        Bitboard b3 = shift<Up >(pawnsOn7) & emptySquares;

        Square ksq = pos.square<KING>(Them);

