  {
      (static_cast<void>(0));
      (static_cast<void>(0));
      (static_cast<void>(0));

      remove_piece(pc, to);
      pc = make_piece(us, PAWN);
      put_piece(pc, to);
  }

  if (type_of(m) == CASTLING)
  {
      Square rfrom, rto;
      do_castling<false>(us, from, to, rfrom, rto);
  }
  else
  {
      move_piece(pc, to, from);

      if (st->capturedPiece)
      {
          Square capsq = to;

          if (type_of(m) == ENPASSANT)
          {
              capsq -= pawn_push(us);

              (static_cast<void>(0));
              (static_cast<void>(0));
              (static_cast<void>(0));
              (static_cast<void>(0));
              (static_cast<void>(0));
          }

          put_piece(st->capturedPiece, capsq);
      }
  }


  st = st->previous;
  --gamePly;

  (static_cast<void>(0));
