void UCI::loop(int argc, char* argv[]) {

  Position pos;
  string token, cmd;

  pos.set(StartFEN, false, &States->back(), Threads.main());

  for (int i = 1; i < argc; ++i)
      cmd += std::string(argv[i]) + " ";

  do {
      if (argc == 1 && !getline(cin, cmd))
          cmd = "quit";

      istringstream is(cmd);

      token.clear();
      is >> skipws >> token;






      if ( token == "quit"
          || token == "stop"
          || (token == "ponderhit" && Search::Signals.stopOnPonderhit))
      {
          Search::Signals.stop = true;
          Threads.main()->start_searching(true);
      }
      else if (token == "ponderhit")
          Search::Limits.ponder = 0;

      else if (token == "uci")
          std::cout << IO_LOCK << "id name " << engine_info(true)
                    << "\n" << Options
                    << "\nuciok" << std::endl << IO_UNLOCK;

      else if (token == "ucinewgame")
      {
          Search::clear();
          Time.availableNodes = 0;
      }
      else if (token == "isready") std::cout << IO_LOCK << "readyok" << std::endl << IO_UNLOCK;
      else if (token == "go") go(pos, is);
      else if (token == "position") position(pos, is);
      else if (token == "setoption") setoption(is);


      else if (token == "flip") pos.flip();
      else if (token == "bench") benchmark(pos, is);
      else if (token == "d") std::cout << IO_LOCK << pos << std::endl << IO_UNLOCK;
      else if (token == "eval") std::cout << IO_LOCK << Eval::trace(pos) << std::endl << IO_UNLOCK;
      else if (token == "perft")
      {
          int depth;
          stringstream ss;

          is >> depth;
          ss << Options["Hash"] << " "
             << Options["Threads"] << " " << depth << " current perft";

          benchmark(pos, ss);
      }
      else
          std::cout << IO_LOCK << "Unknown command: " << cmd << std::endl << IO_UNLOCK;

  } while (token != "quit" && argc == 1);

  Threads.main()->wait_for_search_finished();
}
