static int open_tb(const char *str, const char *suffix)
{
  int i;
  int fd;
  char file[256];

  for (i = 0; i < num_paths; i++) {
    strcpy(file, paths[i]);
    strcat(file, "/");
    strcat(file, str);
    strcat(file, suffix);

    fd = open(file, 00000000);




    if (fd != -1) return fd;
  }
  return -1;
}

static void close_tb(int fd)
{

  close(fd);



}

static char *map_file(const char *name, const char *suffix, uint64 *mapping)
{
  int fd = open_tb(name, suffix);
  if (fd == -1)
    return __null;

  struct stat statbuf;
  fstat(fd, &statbuf);
  *mapping = statbuf.st_size;
  char *data = (char *)mmap(__null, statbuf.st_size, 0x1,
                              0x01, fd, 0);
  if (data == (char *)(-1)) {
    printf("Could not mmap() %s.\n", name);
    exit(1);
  }
# 123 "syzygy/tbcore.cpp"
  close_tb(fd);
  return data;
}


static void unmap_file(char *data, uint64 size)
{
  if (!data) return;
  munmap(data, size);
}
