static void add_to_hash(struct TBEntry *ptr, uint64 key)
{
  int i, hshidx;

  hshidx = key >> (64 - 10);
  i = 0;
  while (i < 5 && TB_hash[hshidx][i].ptr)
    i++;
  if (i == 5) {
    printf("HSHMAX too low!\n");
    exit(1);
  } else {
    TB_hash[hshidx][i].key = key;
    TB_hash[hshidx][i].ptr = ptr;
  }
}

static char pchr[] = {'K', 'Q', 'R', 'B', 'N', 'P'};

static void init_tb(char *str)
{
  int fd;
  struct TBEntry *entry;
  int i, j, pcs[16];
  uint64 key, key2;
  int color;
  char *s;

  fd = open_tb(str, ".rtbw");
  if (fd == -1) return;
  close_tb(fd);

  for (i = 0; i < 16; i++)
    pcs[i] = 0;
  color = 0;
  for (s = str; *s; s++)
    switch (*s) {
    case 'P':
      pcs[1 | color]++;
      break;
    case 'N':
      pcs[2 | color]++;
      break;
    case 'B':
      pcs[3 | color]++;
      break;
    case 'R':
      pcs[4 | color]++;
      break;
    case 'Q':
      pcs[5 | color]++;
      break;
    case 'K':
      pcs[6 | color]++;
      break;
    case 'v':
      color = 0x08;
      break;
    }
  for (i = 0; i < 8; i++)
    if (pcs[i] != pcs[i+8])
      break;
  key = calc_key_from_pcs(pcs, 0);
  key2 = calc_key_from_pcs(pcs, 1);
  if (pcs[1] + pcs[(1 | 8)] == 0) {
    if (TBnum_piece == 254) {
      printf("TBMAX_PIECE limit too low!\n");
      exit(1);
    }
    entry = (struct TBEntry *)&TB_piece[TBnum_piece++];
  } else {
    if (TBnum_pawn == 256) {
      printf("TBMAX_PAWN limit too low!\n");
      exit(1);
    }
    entry = (struct TBEntry *)&TB_pawn[TBnum_pawn++];
  }
  entry->key = key;
  entry->ready = 0;
  entry->num = 0;
  for (i = 0; i < 16; i++)
    entry->num += (ubyte)pcs[i];
  entry->symmetric = (key == key2);
  entry->has_pawns = (pcs[1] + pcs[(1 | 8)] > 0);
  if (entry->num > Tablebases::MaxCardinality)
    Tablebases::MaxCardinality = entry->num;

  if (entry->has_pawns) {
    struct TBEntry_pawn *ptr = (struct TBEntry_pawn *)entry;
    ptr->pawns[0] = (ubyte)pcs[1];
    ptr->pawns[1] = (ubyte)pcs[(1 | 8)];
    if (pcs[(1 | 8)] > 0
              && (pcs[1] == 0 || pcs[(1 | 8)] < pcs[1])) {
      ptr->pawns[0] = (ubyte)pcs[(1 | 8)];
      ptr->pawns[1] = (ubyte)pcs[1];
    }
  } else {
    struct TBEntry_piece *ptr = (struct TBEntry_piece *)entry;
    for (i = 0, j = 0; i < 16; i++)
      if (pcs[i] == 1) j++;
    if (j >= 3) ptr->enc_type = 0;
    else if (j == 2) ptr->enc_type = 2;
    else {
      j = 16;
      for (i = 0; i < 16; i++) {
        if (pcs[i] < j && pcs[i] > 1) j = pcs[i];
        ptr->enc_type = ubyte(1 + j);
      }
    }
  }
  add_to_hash(entry, key);
  if (key2 != key) add_to_hash(entry, key2);
}

void Tablebases::init(const std::string& path)
{
  char str[16];
  int i, j, k, l;

  if (initialized) {
    free(path_string);
    free(paths);
    struct TBEntry *entry;
    for (i = 0; i < TBnum_piece; i++) {
      entry = (struct TBEntry *)&TB_piece[i];
      free_wdl_entry(entry);
    }
    for (i = 0; i < TBnum_pawn; i++) {
      entry = (struct TBEntry *)&TB_pawn[i];
      free_wdl_entry(entry);
    }
    for (i = 0; i < 64; i++)
      if (DTZ_table[i].entry)
        free_dtz_entry(DTZ_table[i].entry);
  } else {
    init_indices();
    initialized = true;
  }

  const char *p = path.c_str();
  if (strlen(p) == 0 || !strcmp(p, "<empty>")) return;
  path_string = (char *)malloc(strlen(p) + 1);
  strcpy(path_string, p);
  num_paths = 0;
  for (i = 0;; i++) {
    if (path_string[i] != ':')
      num_paths++;
    while (path_string[i] && path_string[i] != ':')
      i++;
    if (!path_string[i]) break;
    path_string[i] = 0;
  }
  paths = (char **)malloc(num_paths * sizeof(char *));
  for (i = j = 0; i < num_paths; i++) {
    while (!path_string[j]) j++;
    paths[i] = &path_string[j];
    while (path_string[j]) j++;
  }

  pthread_mutex_init(&(TB_mutex), __null);

  TBnum_piece = TBnum_pawn = 0;
  MaxCardinality = 0;

  for (i = 0; i < (1 << 10); i++)
    for (j = 0; j < 5; j++) {
      TB_hash[i][j].key = 0ULL;
      TB_hash[i][j].ptr = __null;
    }

  for (i = 0; i < 64; i++)
    DTZ_table[i].entry = __null;

  for (i = 1; i < 6; i++) {
    sprintf(str, "K%cvK", pchr[i]);
    init_tb(str);
  }

  for (i = 1; i < 6; i++)
    for (j = i; j < 6; j++) {
      sprintf(str, "K%cvK%c", pchr[i], pchr[j]);
      init_tb(str);
    }

  for (i = 1; i < 6; i++)
    for (j = i; j < 6; j++) {
      sprintf(str, "K%c%cvK", pchr[i], pchr[j]);
      init_tb(str);
    }

  for (i = 1; i < 6; i++)
    for (j = i; j < 6; j++)
      for (k = 1; k < 6; k++) {
        sprintf(str, "K%c%cvK%c", pchr[i], pchr[j], pchr[k]);
        init_tb(str);
      }

  for (i = 1; i < 6; i++)
    for (j = i; j < 6; j++)
      for (k = j; k < 6; k++) {
        sprintf(str, "K%c%c%cvK", pchr[i], pchr[j], pchr[k]);
        init_tb(str);
      }

  for (i = 1; i < 6; i++)
    for (j = i; j < 6; j++)
      for (k = i; k < 6; k++)
        for (l = (i == k) ? j : k; l < 6; l++) {
          sprintf(str, "K%c%cvK%c%c", pchr[i], pchr[j], pchr[k], pchr[l]);
          init_tb(str);
        }

  for (i = 1; i < 6; i++)
    for (j = i; j < 6; j++)
      for (k = j; k < 6; k++)
        for (l = 1; l < 6; l++) {
          sprintf(str, "K%c%c%cvK%c", pchr[i], pchr[j], pchr[k], pchr[l]);
          init_tb(str);
        }

  for (i = 1; i < 6; i++)
    for (j = i; j < 6; j++)
      for (k = j; k < 6; k++)
        for (l = k; l < 6; l++) {
          sprintf(str, "K%c%c%c%cvK", pchr[i], pchr[j], pchr[k], pchr[l]);
          init_tb(str);
        }

  printf("info string Found %d tablebases.\n", TBnum_piece + TBnum_pawn);
}

